// ====================================================================
// Cloudflare 环境变量类型扩展
// ====================================================================
// @opennextjs/cloudflare 定义了全局的 CloudflareEnv 接口
// 但不包含我们自定义的 D1 数据库绑定
// 这里扩展接口，加入 DB 属性（D1 数据库）
// ====================================================================

declare global {
  interface CloudflareEnv {
    // Cloudflare D1 数据库绑定
    DB: D1Database;
  }
}

export {};
